var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"초광역터널 내부. 차원함선 코핀.","ENG":"Inside the hyperwide tunnel. Dimension ship Coffin.","TWN":"超廣域隧道內部，次元艦船科芬。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"오퍼레이터. 방금 탐지 된 이상 파장의 위치 분석은 어떻게 됐지?","JPN":"オペレーター、さっき探知された異常波長の位置分析の結果は？","ENG":"Operator. What's the analysis on the location of the anomalous wavelength we just detected?","TWN":"機務員，剛剛偵測到的異常波長分析位置結果如何？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"네...! 아주 잠깐 동안 나타났다가 사라지긴 했는데, 출처는 저희가 향하는 목적지가 분명합니다!","JPN":"はい……！　一瞬だけ現れて消えましたが、出所は私たちが向かっている目的地に違いありません！","ENG":"Ma'am...! It only appeared briefly before disappearing, but the source is definitely the destination we're heading toward!","TWN":"是……！雖然只出現了一瞬間就消失了，但來源確定是我們的目的地！"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"파장의 유형은 어때? 침식파였어? 아니면 허수 에너지?","JPN":"波長のタイプは？　侵食波？　それとも虚数エネルギー？","ENG":"What about the wavelength type? Was it a Corruption ray? Or Imaginary Energy?","TWN":"波長類型呢？侵蝕波？還是虛空能量？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"둘 다 아니군요. 열람 가능한 관리국 데이터베이스에 따르면, 노르드나빅의 <color=#ffd34c>낙원문</color>이란 시설에서 사용되던 왜곡 파장 기술과 비슷합니다.","JPN":"どちらも違います。閲覧可能な管理局データベースによると、ノルドナビックの<color=#ffd34c>楽園の門</color>という施設で使用されていた歪曲波長技術に類似しています。","ENG":"Neither. According to accessible Administration database records, it's similar to the distortion wavelength technology used at a facility called <color=#ffd34c>Avalon's Gate</color> in Nordnavik.","TWN":"都不是。根據可以瀏覽的管理局資料庫，和諾爾德萊比<color=#ffd34c>樂園門</color>設施使用的扭曲波長技術很相似。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"침식체의 감지기관을 교란시키는 용도죠. 저도 직접 본 적은 없어서, 실제로 그렇게 작동하는진 모르겠지만요.","JPN":"侵食体の感知器官を撹乱させるためのものです。私も実際見たことはないので、本当にそう作動するかは分かりませんが。","ENG":"It's used to disrupt the detection organs of C.O.s. I've never seen it myself, so I can't be sure if it really works that way.","TWN":"那是用來干擾侵蝕體感知器官的。我也沒親眼見過，不確定實際上是不是這樣運作。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"이상하네. 마왕씩이나 되는 존재가... 그런 걸 쓰면서까지 침식체한테 숨을 필요가 있을까?","JPN":"おかしいな。魔王ともあろう存在が……そんなものを使ってまで侵食体から身を隠す必要がある？","ENG":"That's strange. A being on the level of a Demon Lord... would they really need to hide from C.O.s using something like that?","TWN":"真奇怪。像魔王那樣的存在……有必要用這種方式躲避侵蝕體嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"마왕의 왕좌 뿐만 아니라, 침식체가 아닌 존재가 있는 걸지도 모르지.","JPN":"魔王の玉座だけじゃなくて、侵食体じゃない存在がいるのかも。","ENG":"Maybe there are beings there that aren't C.O.s, not just the Demon Lord's throne.","TWN":"也許除了魔王的王座之外，那裡還有不是侵蝕體的存在。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"침식체가 아닌 존재?","JPN":"侵食体じゃない存在？","ENG":"Beings that aren't C.O.s?","TWN":"不是侵蝕體的存在？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하긴. 네헤모트와 싸우던 전장에도 문명의 흔적과 사람의 모습을 한 마왕군이 있었으니까요.","JPN":"まあ、ネヘモトと戦った戦場にも、文明の痕跡や人の姿をした魔王軍が存在していましたからね。","ENG":"Well, even on the battlefield where we fought Nehemoth, there were traces of civilization and Demon Lord forces that looked human.","TWN":"也是。之前和貝赫莫特戰鬥的戰場上，也有文明遺跡和外形像人的魔王軍。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"엑, 그 무시무시한 인형이랑 노래하는 괴물 말고도 뭐가 더 남았다고?","JPN":"げっ、あの恐ろしい人形とか歌う化け物の他にもまだ何かいるの？","ENG":"Ugh, don't tell me there's more than just that terrifying doll and the singing monster?","TWN":"欸？除了那個可怕的人偶和會唱歌的怪物，居然還有別的？"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"필요하다면 싸우겠지만... 괴물도 아닌 사람 모습을 하고 있으면, 쉽지는 않겠네.","JPN":"必要なら戦うけど……化け物じゃなくて、人の見た目をしてるなら、簡単にいかないかもね。","ENG":"If we have to fight them, we will... But if they look human rather than monsters, it won't be easy.","TWN":"必要時當然會戰鬥……但如果對方看起來不是怪物而是人類，就沒那麼容易下手了。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사람의 모습을 하고 있다고 해서 다 같은 편은 아닙니다.","JPN":"人の姿をしているからといって、皆が味方であるわけではありません。","ENG":"Just because something looks human doesn't mean it's on our side.","TWN":"就算外表是人類的，也不一定站在我們這一邊。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"결국, 생김새가 아닌 입장의 차이가 적과 아군을 판가름하는 거니까요.","JPN":"結局、敵味方を区別するのは見た目ではなく、立場の違いなのですから。","ENG":"In the end, what determines allies and enemies isn't appearance, but where they stand.","TWN":"畢竟決定敵我關係的從來不是外表，而是立場。"},"stage":{"bg":"PROLOGUE_02","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"솔직히, 당신의 정체를 알고 있는 이상 쉽게 믿음을 주긴 힘들어.","JPN":"正直あなたの正体を知っている以上、簡単に信じることはできない。","ENG":"To be honest, it's hard to trust you after learning who you are.","TWN":"老實說，在已經知道你的身分的情況下，我很難百分百信任你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가 아는 다른 세계의 사람들은 모두 나에게 칼을 겨눈 적이었거든.","JPN":"私が知っている裏世界の住民は皆、私に刃を向けた敵だったから。","ENG":"The people I've met who came from other worlds were all enemies who tried to kill me.","TWN":"因為我認識的另一個世界的人都曾與我刀刃相向。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이해해요. 전 그냥 낯선 사람도 아니고, 당신들의 세계에 속하지 않은 외부의 존재이니까요.","JPN":"わかります。私はただの人でもなく、あなたたちの世界に属していない外部の存在ですから。","ENG":"I understand. I am not just a stranger, but an outsider who doesn't belong in your world.","TWN":"我能理解。我不僅是個陌生人，還是個不屬於你們的世界的存在。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그런데 말이야.","JPN":"でもさ。","ENG":"But...","TWN":"不過呢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"한편으론 확인해보고 싶은 마음이 있어.","JPN":"一方では、確かめたい気持ちもある。","ENG":"A part of me wants to see.","TWN":"另一方面，我想親眼看看。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신 같은 다른 세계의 사람이 정말 우릴 위해서 싸워줄 수 있는지.","JPN":"あなたのような裏世界の住民が本当に私たちのために戦ってくれるのか。","ENG":"If people from other worlds, like yourself, can really fight for us.","TWN":"像你這樣來自另一個世界的人是否真的能為我們而戰。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"적이 아니라, 같은 목적을 바라보는 아군이 되어줄 수 있는지를 말이야.","JPN":"敵ではなく、同じ目的を持つ味方になってくれるのかを。","ENG":"If you can be an ally with a shared goal and not an enemy.","TWN":"我想確認我們是否能成為目標一致的友軍，而不是敵人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"함께할 기회만 준다면, 증명해 보일게요.","JPN":"お伴させてもらえるのであれば、証明してみせます。","ENG":"If you give me a chance, I'll prove you right.","TWN":"如果給我機會，我會證明給你看。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"당신들의 세계와 제가 지켜야 할 사람을 위해서.","JPN":"あなたたちの世界と、私が守らなければならない人のために。","ENG":"I'll fight for this world and for the person that I must protect.","TWN":"為了你們的世界和我必須保護的人們。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"당신은 아직 더 성장해야 합니다. 그런 작은 이빨로는 아무도 잡아먹지 못해요.","JPN":" あなたはもっと成長しなければなりません。そんな小さな牙では誰も捕食できませんよ。","ENG":"You need to grow. You won’t be able to hunt down anyone with small teeth.","TWN":"你還得繼續成長。那麼小的獠牙連獵物都抓不住。"},"stage":{"bg":"MS_1113_1","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"어쩌면... 당신을 조금 더 일찍 만났다면...","JPN":"もしかしたら……あなたにもう少し早く出会っていれば……","ENG":"If only... If only I had met you sooner...","TWN":"劉米娜……或許……如果能早一點認識你……"},"stage":{"bg":"black","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L33_1","type":"dialog","speaker":"SAVIOR_KNIGHT_NULL_NULL","text":{"KOREA":"조금 더 이야기를 할 수 있었다면... 그랬다면...","JPN":"もう少し早く話ができていれば……もしそうだったら……","ENG":"If only we had more time to talk... then...","TWN":"如果能再多和你聊一聊……那樣的話……"},"stage":{"bg":"black","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SAVIOR_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_MAIN_NPC_ON","text":{"KOREA":"미나 선배? 안색이 안 좋은데, 멀미약 드릴까요? 아니면 초코바?","JPN":"ミナ先輩？　顔色が悪いですけど、酔い止め要りますか？　それともチョコバー？","ENG":"Mina? You don't look well. Should I get you some motion sickness medicine? Or a chocolate bar?","TWN":"米娜前輩？你的臉色不太好，要不要給你暈車藥？還是巧克力棒？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_ON","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...금방 괜찮아질 거야.","JPN":"……心配しなくていいよ。","ENG":"...I'll be fine soon.","TWN":"……很快就會好的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그냥, 생각이 좀 많아졌을 뿐이니까.","JPN":"ただ、頭がごちゃごちゃしちゃってるだけだから。","ENG":"I just have a lot on my mind.","TWN":"我只是突然想了很多事而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"으음...","JPN":"ううん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"GIRL_ANAP_NULL_NULL","text":{"KOREA":"아, 깨어나셨군요. 에클레시아 님.","JPN":"あ、お目覚めになりましたか。エクレシア様。","ENG":"Ah, you're awake, Ms. Ecclesia.","TWN":"啊，你醒了啊，艾可露西亞。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"여긴... 꽃밭?","JPN":"ここは……お花畑？","ENG":"This is... a flower field?","TWN":"這裡是……花田？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GIRL_ANAP_NULL_NULL","text":{"KOREA":"네, 저희 모두 꽃을 따고 있었답니다. 아발론에서 온 작은 왕께 드릴 꽃목걸이를 만들기 위해서요.","JPN":"はい、皆で花を摘んでいました。アバロンからいらっしゃった小さな王に差し上げる花の首飾りを作ろうと思いまして。","ENG":"Yes, we were all picking flowers. To make a flower garland for the little queen from Avalon.","TWN":"對。我們為了編成花環，送給從阿瓦隆來的小王，大家正在採花呢。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"작은 왕...?","JPN":"小さな王……？","ENG":"Little queen...?","TWN":"小王……？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"으음....","JPN":"ううん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"잠든 소녀?","JPN":"女の子が眠っている？","ENG":"A sleeping girl?","TWN":"睡著的少女？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"머리에 뿔이 달려있어.","JPN":"頭に角が生えている。","ENG":"She has horns on her head.","TWN":"頭上長著角。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이 얼굴... 언젠가 보았던 적이 있었는데.","JPN":"この顔……どこかで見たことがある気がするけれど。","ENG":"That face... I've seen it somewhere before.","TWN":"這張臉……我好像曾經在哪裡見過。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그 표정을 보니. 기억이 전부 돌아오신 모양이네요.","JPN":"その顔を見ると、記憶はすべて戻ったようですね。","ENG":"Judging by that expression, it seems all your memories have returned.","TWN":"看你的表情，看來記憶都恢復了呢。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"예하.","JPN":"猊下。","ENG":"Your Eminence.","TWN":"主教。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...아우드라!","JPN":"……アウドラ！","ENG":"...Audra!","TWN":"……奧德拉！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그걸 알면서도 내 앞에 뻔뻔하게 나타나다니. 기만할 셈입니까?","JPN":"それを知ったうえでわたくしの前に現れるとは、なんて図々しい……わたくしを欺瞞するつもりですか？","ENG":"Even knowing that, you still dared to show yourself before me so shamelessly. Are you trying to deceive me?","TWN":"你明知道這件事，居然還厚著臉皮出現在這孩子面前，你打算欺騙她嗎？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"아뇨. 전 주민 분들과 함께 꽃목걸이를 만들러 왔을 뿐인 걸요.","JPN":"まさか。私は住民の方々と花の首飾りを作りに来ただけですよ。","ENG":"No. I only came to make a flower garland together with the residents.","TWN":"不，我只是和居民們一起來做花環而已。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"이 아이를 데려온 게 그대이군요.","JPN":"この子を連れてきたのはあなたですね。","ENG":"So it was you who brought this child here.","TWN":"是你把這孩子帶來的吧？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"우리는 어제, 예언대로 하늘이 갈라지고 어둠이 내려앉는 광경을 봤어요.","JPN":"私たちは昨日、予言通り空が切り裂かれ、闇に覆われる景色を目にしました。","ENG":"Yesterday, just as the prophecy foretold, we witnessed the sky split open and darkness descend.","TWN":"昨天，我們看見了預言說的天空裂開、黑暗降臨的景象。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그날 이후에 한 소녀가 우리의 낙원을 찾아왔으니. 이 소녀는 예언의 일부인 셈이죠.","JPN":"その後一人の少女が楽園にやってきたのですから、この少女は予言の一部といえるでしょう。","ENG":"And after that day, a girl came to our paradise. So this girl must be part of the prophecy.","TWN":"那天之後，有一位少女來到樂園，所以這孩子也是預言的一部分。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"예언이라고? 거짓말!","JPN":"予言ですって？　嘘です！","ENG":"A prophecy? That's a lie!","TWN":"預言？胡說八道！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그대는 아우드라가 아니라 타기리온이잖습니까!","JPN":"あなたはアウドラではなく、タギリオンではありませんか！","ENG":"You're not Audra, you're Thagirion!","TWN":"你不是奧德拉，是塔基里翁！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그런 존재가 만들어낸 세상에서, 대체 무슨 예언을 믿으라는 것입니까?","JPN":"そのような存在が作り出した世界で、いったいどんな予言を信じろと言うのですか？","ENG":"In a world created by a being like you, what kind of prophecy could anyone possibly believe in?","TWN":"在這種傢伙創造的世界裡，你要我們相信什麼預言？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GIRL_ANAP_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MAN_ANAP_NULL_NULL","text":{"KOREA":"우리는 황금나무의 예언을 받드는 낙원의 사도-","JPN":"我らは黄金の木の予言に従う楽園の使徒……","ENG":"We are the Apostles of the Promised Land who serve the prophecy of the Golden Tree.","TWN":"我們是守護黃金樹預言的樂園使徒—"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"GIRL_ANAP_NULL_NULL","text":{"KOREA":"하늘이 갈라지고 어둠이 내려앉아도, 우리는 변함없이 기도하리라.","JPN":"天が裂かれ暗闇が訪れるとしても、我らは変わらず祈ろう。","ENG":"Even if the heavens split apart and darkness descends, we shall pray without faltering.","TWN":"即使天空分裂、黑暗降臨，我們仍會祈禱。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_ANAP_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"WOMAN_ANAP_NULL_NULL","text":{"KOREA":"이 땅에 천사가 내려오고, 노랫소리가 울려 퍼지면, 우리의 정적 또한 심판 받을 지니.","JPN":"この地に天使が降り立ち、歌声が響けば、我らの政敵もまた審判されよう。","ENG":"When angels descend upon this land and song echoes through the air, our foe shall face judgment as well.","TWN":"當天使降臨這片土地、歌聲響起時，我們的寂靜也將受到審判。"},"stage":{"bg":"PATH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WOMAN_ANAP_NULL_NULL","text":{"KOREA":"우리가 비원을 이루는 그날- 가을 끝무렵의 침묵 속에서, 비로소 낙원은 완성되리라.","JPN":"我らの悲願が叶うその日……晩秋の沈黙の中で、ついに楽園は完成されるだろう。","ENG":"On the day our wish is fulfilled. Within the silence at the end of autumn, the Promised Land shall at last be complete.","TWN":"在我們願望實現的那一天—樂園終將在秋末的沉默中完成。"},"stage":{"bg":"PATH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOY_ANAP_NULL_NULL","text":{"KOREA":"영겁 끝에 맞닥뜨리게 될 첫눈을 맞으며-","JPN":"永劫の果てに迎える初雪とともに……","ENG":"As we welcome the first snowfall we will encounter at the end of eternity...","TWN":"在永恆之終迎來的第一場雪—"},"stage":{"bg":"PATH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"낙원의 약속은, 그렇게 이루어지리라.","JPN":"楽園の約束は、そうして叶うだろう。","ENG":"Thus shall the promise of the Promised Land be fulfilled.","TWN":"將如此實現樂園的承諾。"},"stage":{"bg":"PATH","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"에클레시아 님.","JPN":"エクレシア様。","ENG":"Ms. Ecclesia.","TWN":"艾可露西亞。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"아우드라 님은 타기리온과 같은 뿌리에서 태어났을지 언정, 잔혹한 마왕 타기리온과는 다른 분입니다.","JPN":"アウドラ様はタギリオンと同じ根の生まれとはいえ、残酷な魔王タギリオンとは別の方です。","ENG":"Even if Ms. Audra was born from the same root as Thagirion, she is different from the cruel Demon Lord Thagirion.","TWN":"奧德拉或許與塔基里翁出自同一根源，但她與那位殘酷的魔王塔基里翁並不相同。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"그녀는 타기리온의 손에 희생된 저희의 영혼을 낙원에 이르게 해주었고, 우리의 비원을 이루어줄 것을 약속했어요.","JPN":"アウドラ様はタギリオンの手により犠牲となった私たちの魂を楽園に導き、私たちの悲願を叶えることを約束してくださいました。","ENG":"She guided the souls of us who were sacrificed by Thagirion's hand to paradise, and promised to fulfill our long-cherished wish.","TWN":"她讓我們被塔基里翁殺害的靈魂來到樂園，並承諾會替我們實現願望。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OLDLADY_ANAP_NULL_NULL","text":{"KOREA":"우리의 손으로- 마왕 타기리온의 죽음을.","JPN":"私たちの手で……魔王タギリオンに死を。","ENG":"With our own hands... The death of Demon Lord Thagirion.","TWN":"由我們親手—完成魔王塔基里翁的死亡。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"마왕 타기리온이 자신의 죽음을 약속하다니요? 그럴 리가.","JPN":"魔王タギリオンが己の死を約束する？　そんなわけありません。","ENG":"Demon Lord Thagirion promising her own death? That can't be true.","TWN":"魔王塔基里翁會承諾自己的死亡？不可能。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그대는 우릴 기만하고 있는 것이로군요.","JPN":"あなたは私たちを騙していますね。","ENG":"You are deceiving us.","TWN":"你在欺騙我們。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그렇지 않고서야, 이런 허상으로 가득 찬 세계를 만들어 주민들을 가둬놓을 이유가 없을 테니까!","JPN":"そうでないと、こんな偽りの世界を作って、私や住民たちを生かしておく理由がありません！","ENG":"Otherwise, there would be no reason to create a hollow world like this and keep me and the residents alive!","TWN":"不然的話，你沒有理由要創造一個這樣的虛假世界，讓我和居民們活著！"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"저는 누구도 증오의 순환에 갇히지 않는 행복한 세상을 만들고 싶었어요.","JPN":"私は誰も憎悪の連鎖に縛られない幸せな世界が作りたかったのです。","ENG":"I wanted to create a happy world where no one would be trapped in a cycle of hatred.","TWN":"我只是想創造一個沒有任何人被困在仇恨循環中的幸福世界。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"정말 그런 생각을 갖고 있다면, 애초에 저들이 복수를 꿈꾸게 두지 않았을 테지요!","JPN":"本当にそう思っているなら、そもそも彼らが復讐を夢見るのをやめさせていたはずです！","ENG":"If you truly thought that, you wouldn't have let them dream of revenge in the first place!","TWN":"如果你真的有那樣的想法，一開始就不會讓他們懷抱復仇的念頭。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"맞아요.","JPN":"そうです。","ENG":"You're right.","TWN":"沒錯。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"벨레스 님이 당신에게 했던 것처럼... 저 역시 주민들에게 행복했던 추억만을 남겼다면, 그들은 복수를 꿈꾸지 않아도 됐을 거예요.","JPN":"ヴェレス様があなたにそうしたように、私も住民たちに幸せな記憶だけを残しておけば、彼らは復讐を夢見ずに済んだでしょう。","ENG":"Just as Veles did to you... If I had left the residents with only their happy memories, they wouldn't have needed to dream of revenge.","TWN":"如果像貝雷斯對你做的那樣－只留下居民們幸福的回憶，他們就不會夢想復仇了。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"하지만 그런 식으로 진실을 없애버린다면... 그거야말로, 진정 모두를 기만하는 짓이 아닐까요?","JPN":"ですが、そうやって真実をなかったことにするのは……それこそ、皆を騙すことだと思いませんか？","ENG":"But if I erased the truth like that... wouldn't that truly be deceiving everyone?","TWN":"但如果就那樣抹去真相……那不正是真正欺騙所有人的行為嗎？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"머잖아, 낙원을 완성시키기 위한 마지막 조각을 타기리온이 가지고 돌아올 거에요.","JPN":"もうすぐ、楽園を完成させるための最後のピースを、タギリオンが持ち帰ってくるでしょう。","ENG":"Before long, Thagirion will return with the final piece needed to complete the Promised Land.","TWN":"很快，塔基里翁就會帶著完成樂園所需的最後一塊拼圖回來。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그리고 그 마지막 조각을 맞추는 건, 이 소녀의 몫이 되겠죠.","JPN":"そしてそのピースを嵌めるのが、この少女の役割です。","ENG":"And placing that final piece will become this girl's role.","TWN":"而拼上那最後一塊拼圖的人，就是這位少女。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그대는 대체... 무얼 준비하고 있는 것입니까?","JPN":"あなたはいったい……何を準備しているのですか？","ENG":"What in the world... are you preparing?","TWN":"你到底……在準備什麼？"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"낙원의 완성.","JPN":"楽園の完成。","ENG":"The completion of the Promised Land.","TWN":"樂園的完成。"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그리고...","JPN":"そして……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"ANAPILIS","bgm":"THEMA_ECCLESIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"타기리온의 죽음.","JPN":"タギリオンの死。","ENG":"The death of Thagirion.","TWN":"塔基里翁的死亡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이가... 죽었다고?","JPN":"あの子が……死んだ？","ENG":"That child... is dead?","TWN":"那孩子……死了？"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"공주님께선 마지막까지 용감히 맞서 싸우셨습니다.","JPN":"姫様は最後まで勇ましく立ち向かわれました。","ENG":"Her Highness fought bravely to the very end.","TWN":"直到最後一刻，公主都鼓起勇氣戰鬥。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"장벽을 넘어 들이닥친 침식체들을 막으며 백 명이 넘는 민중을 구해내셨죠.","JPN":"障壁を超えて押し寄せてきた侵食体を食い止め、100人を超える民衆を助けたのです。","ENG":"While holding back the C.O.s that broke through the wall, she saved more than a hundred civilians.","TWN":"她在阻擋突破城牆的侵蝕體時，救了超過一百名百姓。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"내가... 절대 밖에 나가지 말라고 경고했을 텐데.","JPN":"アタシは……絶対外に出ないように警告したはずよ。","ENG":"I... told her never to go outside.","TWN":"我……明明警告過她絕對不要離開。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"자물쇠를 부수고 나가신 것 같습니다. 바깥에서 비명 소리가 들리니, 좌시하지 못하셨을 겁니다.","JPN":"鍵を壊して出ていかれたようです。外からの悲鳴をお聞きになり、捨て置くことがおできにならなかったのでしょう。","ENG":"It seems she broke the lock and went out. When she heard the screams outside, she must not have been able to stand by and do nothing.","TWN":"她似乎破壞鎖自己出去了。外面傳來慘叫聲，她一定無法坐視不管。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"모르가나 님은... 그런 분이셨으니까요.","JPN":"モルガナ様は……そういうお方でしたから。","ENG":"...That's the kind of person Ms. Morgana was.","TWN":"莫甘娜……就是那樣的人。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"시국이 좋지 않으니, 장례는 미루도록 하지.","JPN":"情勢が不安定だし、葬儀は先送りにしましょう。","ENG":"The situation is not good, so we will postpone the funeral.","TWN":"現在局勢不穩，葬禮先延期。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"왕가의 분이십니다. 사태가 언제 수습될 지 모르는데 이렇게 방치해둘 수는...","JPN":"王家のお方です。事態がいつ収束するか分からない状況で、このまま放置するわけには……","ENG":"She was of the royal family. We don't know when the situation will be resolved, so we can't simply leave her like this...","TWN":"她是王族的人。何時能平息事態還不知道，不能就這樣放著……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"시신은 나한테 맡겨.","JPN":"遺体はアタシに任せなさい。","ENG":"Leave the body to me.","TWN":"遺體交給我。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네 말처럼 이 사태는 언제 해결될지 몰라. 낙원문도 수도를 계속 지켜주진 못할 테고.","JPN":"アナタの言う通り、この事態はいつ収束するか分からないわ。楽園の門だっていつまで首都を守れるか。","ENG":"As you said, we do not know when this situation will be resolved. Avalon's Gate will not be able to keep protecting the capital forever.","TWN":"就像你說的，這場災難不知道什麼時候才能結束。樂園門也不會永遠守護首都。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"낙원문이... 무너질 거란 말씀입니까? 하지만 노르드나빅은 이 날에 대비해 아주 오래 전부터...","JPN":"楽園の門が……崩れるということですか？　しかしノルドナビックはこの日に備えて遥か昔から……","ENG":"Are you saying... Avalon's Gate will fall? But Nordnavik has been preparing for this day for a very long time...","TWN":"樂園門……會崩壞嗎？可是諾爾德萊比早在很久以前就為了這一天做準備……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"대비한다 해도, 예정된 재난을 막을 순 없는 거야.","JPN":"いくら備えたって、予定された災害は防げないわ。","ENG":"Even if we prepare, we cannot stop a disaster that has already been foretold.","TWN":"就算準備再多，也阻止不了命中注定的災難。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"내가 무슨 수를 써도, 이 아이의 죽음을 막지 못하는 것처럼.","JPN":"アタシがどんな手を使っても、この子を死から守り切れないように。","ENG":"Just as I cannot prevent this child's death, no matter what I do.","TWN":"就像我無論做什麼，都無法阻止這孩子的死亡一樣。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"죄송합니다. 제가 어떻게든 지켜드렸어야 했는데.","JPN":"申し訳ありません。私がなんとしてでも守らなねばならなかったのに。","ENG":"I'm sorry. I should have protected her somehow.","TWN":"對不起，我本來應該想辦法保護她的。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"...네가 해야 할 일은 그런 게 아니야.","JPN":"……アナタのやるべきことはそういうことじゃないわ。","ENG":"...That is not what you should be doing.","TWN":"……那不是你該做的事。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"낙원문의 열쇠를 가지고 남쪽으로 떠나, 총사대장. 수도는 폐하와 내가 군사를 집결시켜 마지막까지 지킨다.","JPN":"楽園の門の鍵を持って南へ向かいなさい、銃士隊長。首都は陛下とアタシが軍を集結させて最後まで守るわ。","ENG":"Take the Key to Avalon's Gate and head south, General Musketeer. His Majesty and I will gather the troops and defend the capital to the very end.","TWN":"帶著樂園門的鑰匙往南走吧，射擊隊長。陛下和我集結軍隊，守護首都直到最後。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"멀린 님? 하지만, 저에게도 수도를 지킬 의무가 있습니다!","JPN":"マーリン様？　ですが、私にも首都を守る義務があります！","ENG":"Ms. Merlin? But I also have a duty to defend the capital!","TWN":"梅林？可是我也有守護首都的責任！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"노르드나빅의 미래는 수도가 아니라 낙원문의 열쇠에 달려있어.","JPN":"ノルドナビックの未来は首都じゃなくて楽園の門の鍵にかかっているわ。","ENG":"Nordnavik's future doesn't depend on the capital, but on the Key to Avalon's Gate.","TWN":"諾爾德萊比的未來不在首都，而在樂園門的鑰匙。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이건... 너와 제 1 총사대가 아니면 할 수 없는 일이야.","JPN":"これは……アナタと第1銃士隊にしかできないことよ。","ENG":"This is... something only you and the 1st Musketeer Division can do.","TWN":"這件事……只有你和第1射擊隊能做到。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"저희에게 맡겨주십시오.","JPN":"私たちにお任せください。","ENG":"Please leave it to us.","TWN":"請交給我們吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_REAL","text":{"KOREA":"공주님을... 부탁드립니다.","JPN":"姫様を……よろしくお願いします。","ENG":"Please... take care of the princess.","TWN":"公主殿下……就拜託你了。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"결국 이번에도, 운명을 바꾸지 못한 거네.","JPN":"結局今回も、運命は変えられなかったのね。","ENG":"In the end, I still couldn't change fate this time either.","TWN":"結果這一次，還是沒能改變命運。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만...","JPN":"でも……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"널 이대로 포기하진 않겠어.","JPN":"このままアナタを諦めたりはしないわ。","ENG":"I won't give up on you like this.","TWN":"我不會就這樣放棄你。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"설령, 마왕의 심장을 쓰는 한이 있더라도.","JPN":"たとえ、魔王の心臓を使うことになるとしても。","ENG":"Even if it means using the Demon Lord's heart.","TWN":"即使要用上魔王的心臟。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CURIAN_BORDER_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"넌 마왕이 아니라 임금님이야.","JPN":"あなたは魔王じゃなくて、王様よ。","ENG":"You're not a Demon Lord. You're a queen.","TWN":"你不是魔王，你只是國王而已。"},"stage":{"bg":"WHITE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"뭐, 자길 뭐라고 부르든 네 마음이겠지만.","JPN":"まあ、自分のことをどう呼ぼうがあなたの自由でしょうけど。","ENG":"Well, call yourself whatever you want.","TWN":"不過隨你高興怎麼稱呼自己。"},"stage":{"bg":"WHITE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 악마가 원하는 건 작은 왕이지, 네가 아냐.","JPN":"あの悪魔が望んでいるのは小さな王で、あなたじゃないの。","ENG":"What that demon wants is the little queen, not you.","TWN":"那個惡魔想要的是我，不是你。"},"stage":{"bg":"WHITE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L45_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하지만 네가 없으면, 반쪽짜리 영혼을 가진 작은 왕은 영원히 깨어날 수 없겠지.","JPN":"でもあなたがいないと、不完全な魂を持つ小さな王は永遠に目覚められないでしょうね。","ENG":"But without you, the little queen, with only half a soul, can never awaken.","TWN":"但如果沒有你，只有半個靈魂的我永遠也無法甦醒。"},"stage":{"bg":"WHITE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그때 그 악마는 뭘 원할까? 너? 아니면...","JPN":"その時、あの悪魔は何を望むと思う？　あなた？　それとも……","ENG":"When that time comes, what do you think the demon will want? You? Or...","TWN":"那麼，那個惡魔真正想要的是什麼？是你？還是……"},"stage":{"bg":"WHITE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"임금님을 움직이게 하는, 너라는 조각?","JPN":"王様を動かすための、あなたという破片？","ENG":"...the Fragment you are that lives in the little majesty?","TWN":"那個被稱作你，能夠驅動國王的碎片？"},"stage":{"bg":"WHITE","bgm":"THEMA_CITY_CHAMBER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GIRL_ANAP_NULL_NULL","text":{"KOREA":"보세요, 아우드라 님.","JPN":"見てください、アウドラ様。","ENG":"Look, Ms. Audra.","TWN":"請看，奧德拉。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GIRL_ANAP_NULL_NULL","text":{"KOREA":"작은 왕께서 눈물을 흘리고 계세요.","JPN":"小さな王が涙を流しています。","ENG":"The little queen is shedding tears.","TWN":"小王正在流淚。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GIRL_ANAP_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"네, 저도 보여요.","JPN":"ええ、私にも見えています。","ENG":"Yes, I can see it as well.","TWN":"對，我也看見了。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"작은 왕께선, 지금 아주 슬픈 꿈을 꾸고 계신 것 같네요.","JPN":"小さな王は、今とても悲しい夢を見ているようですね。","ENG":"It seems the little queen is having a very sad dream right now.","TWN":"小王現在正在做一個非常悲傷的夢。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"꿈을 통해 자신이 누구인지 깨닫고, 진정으로 겨눠야 할 적이 누구인지도 알게 되겠죠.","JPN":"夢を通して自分が何者かを知り、本当の敵は誰なのかも知ることになるでしょう。","ENG":"Through that dream, she will come to realize who she is, and who her true enemy is.","TWN":"透過夢境，她會明白自己是誰，也會知道真正應該瞄準的敵人是誰。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"황금나무의 예언을 이루기 위해.","JPN":"黄金の木の予言を叶えるために。","ENG":"To fulfill the prophecy of the Golden Tree.","TWN":"為了實現黃金樹的預言。"},"stage":{"bg":"ANAPILIS","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};